// previewTypeCode returns the type code used for preview based on group.
func previewTypeCode(group string) string {
	if group == "po" {
		return "PO"
	}
	return "TDC"
}

// jsEsc escapes a string for safe inclusion in a JavaScript single-quoted string literal.
func jsEsc(s string) string {
	s = strings.ReplaceAll(s, `\`, `\\`)
	s = strings.ReplaceAll(s, `'`, `\'`)
	return s
}

